import{_ as a}from"./chunks/features.uypcYnWI.js";import{_ as n,c as s,o as t,a1 as i}from"./chunks/framework.DDNAyvCW.js";const l="/assets/skill2.OkENhr0n.webp",o="/assets/skill4.CkgfOAO_.webp",r="/assets/skill5.CfiyDcLU.webp",p="/assets/skill6.B-n-mjkO.webp",c="/assets/skill7.CBTgnhb8.webp",h="/assets/skill8.BsS5uuLn.webp",d="/assets/skill9.XyI5en6S.webp",u="/assets/skill10.BjZcPf8t.webp",m="/assets/skill11.Cccq3RE0.webp",q=JSON.parse('{"title":"Agent Skills + Qwen Model, A New Evolution in DEVOPS","description":"","frontmatter":{"title":"Agent Skills + Qwen Model, A New Evolution in DEVOPS","author":"Aliyun Blogs","date":"2026-2-25","top":true,"sticky":15,"comment":false,"category":"Technical","tags":["Agent","Skills","Confluence","Aliyun","AIOPS"],"blog":"post","aside":"left","sidebar":false,"prev":false,"next":false},"headers":[],"relativePath":"blog/posts/skills.md","filePath":"blog/posts/skills.md"}'),g={name:"blog/posts/skills.md"};function k(f,e,b,y,S,w){return t(),s("div",null,e[0]||(e[0]=[i('<p>By integrating the Qwen model, Chaterm Agent Skills can package DevOps experience into executable skills, allowing the AI ​​assistant to automatically execute standard processes.</p><p>Leveraging the powerful semantic understanding, command generation, and agent task planning capabilities of the Qwen model, Chaterm provides users with a intelligent DevOps experience, enabling rapid troubleshooting and recovery based on past experience when failures occur.</p><hr><h2 id="a-real-troubleshooting-experience-at-3-am" tabindex="-1">A real troubleshooting experience at 3 AM <a class="header-anchor" href="#a-real-troubleshooting-experience-at-3-am" aria-label="Permalink to &quot;A real troubleshooting experience at 3 AM&quot;">​</a></h2><p>Last Wednesday at 3 AM, I was woken up by an alert from my cloud monitoring system.</p><p>“【Confluence System】 <a href="http://192.168.0.1:8090/pages/#all-updates" target="_blank" rel="noreferrer">http://192.168.0.1:8090/pages/#all-updates</a> inaccessible!”</p><p>I groggily turned on my computer, connected to the cloud server via Chaterm, and started typing commands: netstat -nplut, top, systemctl status confluence, tail -f… Looking at the screen full of output, I rubbed my eyes and analyzed the problem, spending 20 minutes before finally finding the issue: the system load was too high in the early morning, causing an abnormal shutdown. The automatic backup gzip process was constantly consuming resources, causing the system service to repeatedly fail to restart.</p><p>【Inner monologue】If I had a special skill at the time, I probably could have fixed it in 3 minutes.</p><p><img src="'+l+'" alt=""></p><p>This is what we&#39;ll be discussing today: Skills. It&#39;s not just another AI concept, but a tool that truly helps you &quot;package&quot; your operational experience into actionable skills. Today, we&#39;ll start by explaining what Skills are, how they work, how to write a good Skill, and finally, we&#39;ll implement them in a real-world Alibaba Cloud-based operational scenario using Chaterm.</p><h2 id="introduction-to-chaterm-skills" tabindex="-1">Introduction to Chaterm Skills <a class="header-anchor" href="#introduction-to-chaterm-skills" aria-label="Permalink to &quot;Introduction to Chaterm Skills&quot;">​</a></h2><h3 id="what-is-chaterm" tabindex="-1">What is Chaterm? <a class="header-anchor" href="#what-is-chaterm" aria-label="Permalink to &quot;What is Chaterm?&quot;">​</a></h3><p>Chaterm is an open-source AI-powered smart terminal and SSH client. It aims to reconstruct the traditional command-line experience through natural language interaction. Its goal is to become your intelligent DevOps co-pilot. Currently, it supports multiple environments including Mac, Windows, Linux, iOS, and Android. Chaterm aims to solve pain points in large-scale cloud operations such as batch operations, complex troubleshooting, and difficult security management. It directly embeds AI Agent capabilities into the terminal, creating a &quot;conversational terminal management tool&quot; to help server-side developers, DevOps engineers, and cloud computing professionals achieve intelligent and large-scale management of cloud resources.</p><p><img src="'+a+`" alt=""></p><h3 id="what-are-skills" tabindex="-1">What are Skills? <a class="header-anchor" href="#what-are-skills" aria-label="Permalink to &quot;What are Skills?&quot;">​</a></h3><p>The concept of <strong>Skills</strong> was first proposed by Anthropic. Simply put, it allows users to encapsulate their professional knowledge, operational procedures, and best practices into Skills, which AI can then automatically recognize and execute.</p><p>As this approach has matured and gained widespread acceptance within the community, Skills have become a standard extension specification supported by most AI coding and AI tools.</p><p>From Claude Code, Qoder, Cursor to Chaterm, many AI tools have implemented their own Skills systems based on this specification.</p><p>Chaterm is no exception. Based on this specification, it allows operations engineers to encapsulate daily checklists, application/database deployment processes, troubleshooting processes, performance optimization steps, etc., on Alibaba Cloud into Skills. In this way, the AI ​​assistant is no longer a <strong>general assistant</strong>, but a truly business-understanding <strong>expert assistant</strong>.</p><h3 id="standard-structure-of-skills" tabindex="-1">Standard Structure of Skills <a class="header-anchor" href="#standard-structure-of-skills" aria-label="Permalink to &quot;Standard Structure of Skills&quot;">​</a></h3><p>A Skill typically exists as a folder containing three main items:</p><p>A user manual (SKILL.md), an operation script, and reference materials.</p><table tabindex="0"><thead><tr><th>Content</th><th>Purpose</th></tr></thead><tbody><tr><td>SKILL.md</td><td>Clearly describes the process using natural language (including contextual information such as use cases, usage methods, usage steps, and precautions)</td></tr><tr><td>Script</td><td>The specific script code that the Agent can execute</td></tr></tbody></table><p>Reference | Referenced documents, referenced templates, and related contextual file information</p><p>You can think of a Skill as a packaged &quot;skill book.&quot; It encapsulates the domain knowledge, operational procedures, tools, and best practices needed to complete a specific task. When AI faces a corresponding request, it can execute the task autonomously and methodically, like an experienced expert.</p><p>In short: If you compare an Agent to a brain with great potential, then Skills are like a series of reusable &quot;skill manuals&quot; for that brain. With them, an Agent can transform from a &quot;jack-of-all-trades&quot; into a &quot;master&quot; in a specific domain.</p><p>Each SKILL.md file follows the following format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: skill-name</span></span>
<span class="line"><span>description: Skill description</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Skill Title</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Workflow Step</span></span>
<span class="line"><span>[Detailed workflow and commands]</span></span></code></pre></div><p>It&#39;s that simple. AI sees the skill and knows what to do.</p><h3 id="how-do-chaterm-skills-work" tabindex="-1">How do Chaterm Skills work? <a class="header-anchor" href="#how-do-chaterm-skills-work" aria-label="Permalink to &quot;How do Chaterm Skills work?&quot;">​</a></h3><p><img src="`+o+'" alt=""></p><p>In Chaterm, the Skills workflow is as follows:</p><p><strong>1. Loading Phase:</strong> When Chaterm starts, it scans the Skills directory and reads all SKILL.md files.</p><p><strong>2. Injection Phase:</strong> Enabled Skills are injected into the AI&#39;s system prompts, informing the AI ​​which skills are available.</p><p><strong>3. Recognition Phase:</strong> When you submit a request, the AI ​​analyzes it to determine if a particular Skill is needed.</p><p><strong>4. Execution Phase:</strong> If a match is found, the AI ​​calls the <code>use_skill</code> tool to obtain the complete Skill content and then executes it according to the workflow.</p><p>The entire process is transparent to the user. You only need to say &quot;Check the Confluence system status on Alibaba Cloud ECS,&quot; and the AI ​​will automatically recognize and use the <code>Confluence-health-check</code> Skill.</p><h3 id="why-chaterm-skills-are-suitable-for-operations-and-maintenance-scenarios" tabindex="-1">Why Chaterm Skills are Suitable for Operations and Maintenance Scenarios <a class="header-anchor" href="#why-chaterm-skills-are-suitable-for-operations-and-maintenance-scenarios" aria-label="Permalink to &quot;Why Chaterm Skills are Suitable for Operations and Maintenance Scenarios&quot;">​</a></h3><p><img src="'+r+`" alt=""></p><p>Operations and maintenance (O&amp;M) work has several characteristics that make Skills particularly valuable:</p><h3 id="_1-high-standardization" tabindex="-1">1. High Standardization <a class="header-anchor" href="#_1-high-standardization" aria-label="Permalink to &quot;1. High Standardization&quot;">​</a></h3><p>System health checks, application middleware/database service deployment, log analysis, and troubleshooting all have relatively standardized processes. A senior O&amp;M operator&#39;s manual can often cover 80% of scenarios.</p><h3 id="_2-many-repetitive-operations" tabindex="-1">2. Many Repetitive Operations <a class="header-anchor" href="#_2-many-repetitive-operations" aria-label="Permalink to &quot;2. Many Repetitive Operations&quot;">​</a></h3><p>You might need to check system status, deploy services, analyze logs, and troubleshoot problems every day. Describing the process again each time is too tedious. Skills allows you to &quot;write it once, use it forever.&quot;</p><h3 id="_3-difficulty-in-passing-on-experience" tabindex="-1">3. Difficulty in Passing on Experience <a class="header-anchor" href="#_3-difficulty-in-passing-on-experience" aria-label="Permalink to &quot;3. Difficulty in Passing on Experience&quot;">​</a></h3><p>How can a newcomer, Li, quickly learn from the troubleshooting experience of veteran Wang? Writing documentation? Reading code? Neither is as effective as giving them a Skill and letting them follow the AI&#39;s instructions.</p><h3 id="_4-high-cost-of-errors" tabindex="-1">4. High Cost of Errors <a class="header-anchor" href="#_4-high-cost-of-errors" aria-label="Permalink to &quot;4. High Cost of Errors&quot;">​</a></h3><p>Incorrect operations in the production environment can have serious consequences. Skills solidify best practices, reducing human error.</p><h2 id="implementing-a-chaterm-skill-in-an-alibaba-cloud-operations-scenario" tabindex="-1">Implementing a Chaterm Skill in an Alibaba Cloud Operations Scenario <a class="header-anchor" href="#implementing-a-chaterm-skill-in-an-alibaba-cloud-operations-scenario" aria-label="Permalink to &quot;Implementing a Chaterm Skill in an Alibaba Cloud Operations Scenario&quot;">​</a></h2><p>No amount of theory is as effective as hands-on practice. Below, I&#39;ll guide you through the complete process from Skill creation to usage.</p><h3 id="scenario-creating-a-confluence-system-anomaly-check-skill" tabindex="-1">Scenario: Creating a &quot;Confluence System Anomaly Check&quot; Skill <a class="header-anchor" href="#scenario-creating-a-confluence-system-anomaly-check-skill" aria-label="Permalink to &quot;Scenario: Creating a &quot;Confluence System Anomaly Check&quot; Skill&quot;">​</a></h3><p>Assume you have deployed Confluence on an Alibaba Cloud ECS instance and frequently encounter system anomalies. You want to create a dedicated skill to check and handle these issues.</p><h3 id="step-1-planning-the-skill" tabindex="-1">Step 1: Planning the Skill <a class="header-anchor" href="#step-1-planning-the-skill" aria-label="Permalink to &quot;Step 1: Planning the Skill&quot;">​</a></h3><p>First, clarify:</p><p><strong>Name:</strong> confluence-health-check;</p><p><strong>Description:</strong> Check the Confluence system status, including service status, service ports, CPU, memory, disk, and logs;</p><h3 id="step-2-designing-the-workflow-of-skill-md" tabindex="-1">Step 2: Designing the Workflow of SKILL.md <a class="header-anchor" href="#step-2-designing-the-workflow-of-skill-md" aria-label="Permalink to &quot;Step 2: Designing the Workflow of SKILL.md&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: confluence-health-check</span></span>
<span class="line"><span>description: Check the Confluence system status, including service status, service ports, CPU, memory, disk, and logs.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Confluence System Check</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Workflow</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Step 1: Check Service Status and Port</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Switch to Root Privileges</span></span>
<span class="line"><span>sudo su -</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Service Status</span></span>
<span class="line"><span>systemctl status confluence</span></span>
<span class="line"><span>netstat -nplut | grep 8090</span></span>
<span class="line"><span>netstat -nplut | grep 8091</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Step Two: Check System Resources</span></span>
<span class="line"><span></span></span>
<span class="line"><span># CPU and Memory</span></span>
<span class="line"><span>top -bn1 | head -20</span></span>
<span class="line"><span>free -h</span></span>
<span class="line"><span>uptime</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Memory usage</span></span>
<span class="line"><span></span></span>
<span class="line"><span>free -h</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Disk usage</span></span>
<span class="line"><span></span></span>
<span class="line"><span>df -h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Step 3: Check processes and logs</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Process status</span></span>
<span class="line"><span>ps aux | grep confluence | grep -v grep</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Step 5: Check System Logs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>View error messages in the system log and Confluence log:</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Confluence-related errors in the system log</span></span>
<span class="line"><span></span></span>
<span class="line"><span>journalctl -u confluence -p err --no-pager | tail -20</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Confluence application log</span></span>
<span class="line"><span></span></span>
<span class="line"><span>tail -50 /var/atlassian/application-data/confluence/log/atlassian-confluence.log 2&gt;/dev/null</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Check recent errors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>grep -i &quot;error\\|exception\\|fail&quot; /var/atlassian/application-data/confluence/log/*.log 2&gt;/dev/null | tail -30</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## After collecting data, analyze it according to the following criteria:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 1. Service Status</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Normal status: \`systemctl status\` displays \`active (running)\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Abnormal status: If it displays \`inactive\`, \`failed\`, or... \`dead\`, requires immediate action.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 2. Port Status</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Port 8090: Must be in \`LISTEN\` state.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Port 8091: Must be in \`LISTEN\` state if HTTPS is enabled.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 3. CPU Usage</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Average Load: Should be less than the number of CPU cores.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- CPU Utilization: Should be below 50% during normal operation.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 4. Memory Usage</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Available Memory: Should be greater than 10% of total memory.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 5. Disk Usage</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- System Disk (/): Available space should be greater than 10%.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Data Directory (/data): Available space should be greater than 10%.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 6. Process Status</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Number of Processes: Typically, there should be multiple Java processes (main process + worker processes).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Process Resource Usage: If a single process uses excessively high resources, there may be a memory leak or performance issue.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 7. Log Analysis</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Error Log: Check for recurring error patterns</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Exception Information: Pay attention to critical exceptions such as \`OutOfMemoryError\` and \`ConnectionException\`.</span></span></code></pre></div><h3 id="step-3-create-a-skill-in-chaterm" tabindex="-1">Step 3: Create a Skill in Chaterm <a class="header-anchor" href="#step-3-create-a-skill-in-chaterm" aria-label="Permalink to &quot;Step 3: Create a Skill in Chaterm&quot;">​</a></h3><p><strong>Method A: Create via UI</strong></p><ol><li><p>Open Chaterm</p></li><li><p>Click the settings icon on the left → Select “Skills”</p></li><li><p>Click the “Create Skill” button in the upper right corner</p></li><li><p>Fill out the form:</p></li></ol><p><strong>Name:</strong> confluence-health-check</p><p><strong>Description:</strong> Checks the Confluence system status, including service status, service port, CPU, memory, and disk</p><p><strong>Content:</strong> Copy the complete Skill content above (starting from ---)</p><ol start="5"><li>Click “Create”</li></ol><p><strong>Method B: Direct File Creation</strong></p><ol><li><p>Click the &quot;Open Folder&quot; button on the Skills page.</p></li><li><p>Create a new folder named confluence-health-check.</p></li><li><p>Create a file named SKILL.md in this folder.</p></li><li><p>Copy the Skill content into the file.</p></li><li><p>Return to the Chaterm and click the &quot;Reload&quot; button.</p></li></ol><h3 id="step-4-using-the-skill" tabindex="-1">Step 4: Using the Skill <a class="header-anchor" href="#step-4-using-the-skill" aria-label="Permalink to &quot;Step 4: Using the Skill&quot;">​</a></h3><p>After creation, in the Chaterm dialog window, you can directly describe your requirements:</p><p>\`\`Check the Confluence system status on Alibaba Cloud ECS\`\`\`</p><p>AI will automatically recognize and use the confluence-health-check Skill, performing the operation according to the workflow.</p><p><img src="`+p+`" alt=""></p><h3 id="step-5-optimization-and-iteration" tabindex="-1">Step 5: Optimization and Iteration <a class="header-anchor" href="#step-5-optimization-and-iteration" aria-label="Permalink to &quot;Step 5: Optimization and Iteration&quot;">​</a></h3><p>After using it a few times, you might find:</p><ul><li><p>Some commands are too slow and need optimization.</p></li><li><p>Some execution command items are missing and need to be added.</p></li><li><p>The execution steps are incomplete and need adjustment.</p></li></ul><p>At this point, you can:</p><ol><li><p>Edit the Skill file (directly modify the file in the Skills directory).</p></li><li><p>Reload Skills.</p></li><li><p>Test again.</p></li></ol><p>This is the advantage of Skills: it can be continuously optimized and gets better with use.</p><h2 id="technical-implementation-of-chaterm-skills" tabindex="-1">Technical Implementation of Chaterm Skills <a class="header-anchor" href="#technical-implementation-of-chaterm-skills" aria-label="Permalink to &quot;Technical Implementation of Chaterm Skills&quot;">​</a></h2><p>Here we&#39;ll look at the technical implementation of Chaterm.</p><p><strong>Chaterm Skills：</strong></p><p>Skills Storage Structure</p><p>In a Chapter, Skills are stored in the user data directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Chaterm/skills/</span></span>
<span class="line"><span>├── confluence-health-check/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>├── log-analyzer/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>└── mysql-deploy/</span></span>
<span class="line"><span>    ├── SKILL.md</span></span>
<span class="line"><span>    ├── scripts/</span></span>
<span class="line"><span>    │   └── db_init.py</span></span>
<span class="line"><span>    └── references/</span></span>
<span class="line"><span>        └── workflow.md</span></span></code></pre></div><p>Each Skill is a folder, and it must contain a SKILL.md file. You can also put resource files there, such as scripts and templates.</p><p><strong>Skills Loading Mechanism</strong></p><p>When Chatem starts, it will:</p><ol><li>Parse each SKILL.md file:</li></ol><ul><li><p>Extract the frontmatter (name, description)</p></li><li><p>Read the complete content</p></li><li><p>Scan resource files</p></li></ul><ol start="2"><li>Register with the system:</li></ol><ul><li><p>Store in an in-memory Map</p></li><li><p>Load the enabled status from the database</p></li><li><p>Inject system hints into the AI</p></li></ul><p><strong>Skills Triggering Mechanism</strong></p><p>When the AI ​​receives your request:</p><p><strong>1. Analyze the task:</strong> Understand what you want to do</p><p><strong>2. Match Skills:</strong> See which of the available Skills&#39; descriptions matches your needs</p><p><strong>3. Call tools:</strong> If a match is found, call the <code>use_skill</code> tool, passing in the Skill name</p><p><strong>4. Retrieve content:</strong> The system returns the complete Skill content (including workflow, analysis guidelines, etc.)</p><p><strong>5. Execute the process:</strong> The AI ​​calls other tools (such as...) according to the steps in the Skill. The <code>execute_command</code> command completes the task.</p><p>The entire process is automatic; you don&#39;t need to manually specify which skill to use.</p><h3 id="chaterm-integration-with-the-qwen-large-scale-model" tabindex="-1">Chaterm Integration with the Qwen Large-Scale Model: <a class="header-anchor" href="#chaterm-integration-with-the-qwen-large-scale-model" aria-label="Permalink to &quot;Chaterm Integration with the Qwen Large-Scale Model:&quot;">​</a></h3><p>The Qwen Large-Scale Model is a massively multi-scale language model independently developed by Alibaba Group. It boasts powerful language understanding, multi-language support, code generation, and logical reasoning capabilities. As the largest global open-source model family, it is widely used by hundreds of thousands of developers worldwide. Qwen has repeatedly ranked highly in authoritative international benchmarks such as Gartner, IDC, Forrester, and Omdia, achieving internationally advanced performance levels.</p><p>Currently, the Qwen Large-Scale Model and Chaterm have joined forces, integrating Qwen-Plus and Qwen-Turbo as recommendation models in Chaterm&#39;s Chat, Command, and Agent modes. The provided AI Agent capabilities are directly embedded into the terminal and combined with the powerful capabilities of the Qwen Large-Scale Model to create a &quot;conversational terminal management tool.&quot; This helps server-side developers, DevOps engineers, and cloud computing professionals achieve intelligent and large-scale management of cloud resources, ushering in a new paradigm for cloud operations and maintenance.</p><p><img src="`+c+'" alt=""></p><p>Qwen recently launched its latest flagship inference model, Qwen3-Max-Thinking, which has significantly improved in factual knowledge, complex reasoning, instruction compliance, alignment with human preferences, and agent capabilities. In 19 authoritative benchmark tests, its performance rivals top models such as GPT-5.2-Thinking, Claude-Opus-4.5, and Gemini 3 Pro. Qwen3-Max-Thinking is now available on Alibaba Cloud&#39;s Bailian Platform and Qwen Chat for users to quickly experience.</p><h2 id="one-click-direct-connection-to-alibaba-cloud-bastion-host-assets-via-chaterm" tabindex="-1">One-click direct connection to Alibaba Cloud Bastion Host assets via Chaterm <a class="header-anchor" href="#one-click-direct-connection-to-alibaba-cloud-bastion-host-assets-via-chaterm" aria-label="Permalink to &quot;One-click direct connection to Alibaba Cloud Bastion Host assets via Chaterm&quot;">​</a></h2><p><img src="'+h+'" alt=""></p><p>Beyond Agent Skills, Chaterm lets you say goodbye to traditional methods and achieve true &quot;one-click connection&quot;.</p><p>The traditional method requires:</p><ul><li>Open the Alibaba Cloud console → Locate the asset → Copy the IP → Configure SSH → Enter the password → Connect...</li></ul><p>Now, <strong>Chaterm supports one-click connection</strong>.</p><p><img src="'+d+'" alt=""></p><p><strong>Features:</strong></p><p>Refresh and synchronize the asset list for more efficient management.</p><p>Click on an asset to connect directly, no manual configuration required.</p><p>Automatic management of security credentials, eliminating repetitive input.</p><p><strong>Configuration Method:</strong></p><ol><li><p>Configure Alibaba Cloud Bastion Host authentication information in Chaterm.</p></li><li><p>Refresh and synchronize the bastion host asset list.</p></li><li><p>Click on the asset to quickly connect.</p></li></ol><p><strong>Chaterm makes Alibaba Cloud Bastion Host asset management simpler and more efficient.</strong></p><p><img src="'+u+'" alt=""></p><h2 id="how-to-use-chaterm-skills-effectively" tabindex="-1">How to Use Chaterm Skills Effectively <a class="header-anchor" href="#how-to-use-chaterm-skills-effectively" aria-label="Permalink to &quot;How to Use Chaterm Skills Effectively&quot;">​</a></h2><p>Writing skills doesn&#39;t start from scratch; there are many existing resources to refer to.</p><h3 id="skills-standard-specification" tabindex="-1">Skills Standard Specification <a class="header-anchor" href="#skills-standard-specification" aria-label="Permalink to &quot;Skills Standard Specification&quot;">​</a></h3><p>Skills follow an open standard specification. Understanding the specification helps in writing more compatible skills.</p><p><strong>Core Requirements:</strong></p><p>Must include a frontmatter (name and description)</p><p>Support resource files (scripts, referenced documentation, etc.)</p><h3 id="skills-community-resources" tabindex="-1">Skills Community Resources <a class="header-anchor" href="#skills-community-resources" aria-label="Permalink to &quot;Skills Community Resources&quot;">​</a></h3><p>Anthropic Skills examples: <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">https://github.com/anthropics/skills</a></p><p>Chaterm Skills examples for operations and maintenance scenarios: <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">https://github.com/chaterm/terminal-skills</a></p><p>Many other repositories on GitHub provide Skills examples, which will not be listed here.</p><p>You can use these examples to:</p><ol><li><p>Directly copy and use them in Chaterm</p></li><li><p>Modify them to your own version</p></li><li><p>Learn their structure and syntax</p></li></ol><h3 id="summary-what-has-chaterm-agent-skills-changed" tabindex="-1">Summary: What has Chaterm Agent Skills changed? <a class="header-anchor" href="#summary-what-has-chaterm-agent-skills-changed" aria-label="Permalink to &quot;Summary: What has Chaterm Agent Skills changed?&quot;">​</a></h3><p><img src="'+m+'" alt=""></p><p>Let&#39;s return to the initial scene at 3 AM.</p><p><strong>Before:</strong></p><ul><li><p>Manually executing commands</p></li><li><p>Finding problems from a pile of output</p></li><li><p>Relying on personal experience</p></li><li><p>Easily overlooking key checks</p></li><li><p>Having to start over every time</p></li></ul><p><strong>Now:</strong></p><ul><li><p>AI automates standard processes</p></li><li><p>Generates structured diagnostic reports</p></li><li><p>Follows team best practices</p></li><li><p>Complete checks, no omissions</p></li><li><p>Created once, used permanently</p></li></ul><p>Skills isn&#39;t meant to replace operations engineers, but rather to make the AI ​​assistant truly your &quot;expert assistant.&quot; It solidifies your experience, allowing the team to share it and enabling newcomers to quickly get started.</p><p>Most importantly, Skills is open and customizable. You can create your own Skills based on your needs. Start by solving real-world problems and gradually build your Skills library.</p><h3 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h3><ol><li><p><strong>Try Chaterm:</strong> If you haven&#39;t used it before, download and try it from <a href="https://chaterm.cn/download/" target="_blank" rel="noreferrer">https://chaterm.cn/download/</a></p></li><li><p><strong>View Examples:</strong> View the official Skills examples on GitHub.</p></li><li><p><strong>Create Your First Skill:</strong> Start with your most frequently used operations and write a simple skill.</p></li><li><p><strong>Share and Collaborate:</strong> Share your Skills in the community or learn from others.</p></li></ol><p>The value of Skills lies in their use. Start writing your first Skill now!!!</p><h3 id="related-websites" tabindex="-1">Related Websites: <a class="header-anchor" href="#related-websites" aria-label="Permalink to &quot;Related Websites:&quot;">​</a></h3><p>Chaterm Website: <a href="https://chaterm.ai" target="_blank" rel="noreferrer">https://chaterm.ai</a></p><p>Aliyun Bailian: <a href="https://www.aliyun.com/product/bailian" target="_blank" rel="noreferrer">https://www.aliyun.com/product/bailian</a></p><p>Qwen Chat: <a href="https://chat.qwen.ai" target="_blank" rel="noreferrer">https://chat.qwen.ai</a></p><p>GitHub Repository: <a href="https://github.com/chaterm/Chaterm" target="_blank" rel="noreferrer">https://github.com/chaterm/Chaterm</a></p><p>Skills Examples: <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">https://github.com/chaterm/terminal-skills</a></p>',150)]))}const x=n(g,[["render",k]]);export{q as __pageData,x as default};
